command:
python3 - <<'PY'
import subprocess, json, base64
repo='xbmc/kodiai'
for path in ['kodiai.yml','.kodiai.yml','.github/kodiai.yml','biome.json','prettier.config.js','package.json']:
    p=subprocess.run(['gh','api',f'repos/{repo}/contents/{path}','-f','ref=main','--jq','{path:.path,sha:.sha,encoding:.encoding,content:.content}'],text=True,stdout=subprocess.PIPE,stderr=subprocess.PIPE,timeout=20)
    print(f'content_probe {path} exit={p.returncode}')
    if p.returncode==0 and p.stdout.strip():
        try:
            d=json.loads(p.stdout)
            content=d.get('content') or ''
            if d.get('encoding')=='base64':
                text=base64.b64decode(content).decode('utf-8','replace')
                print('---begin '+path+'---')
                print('\n'.join(text.splitlines()[:80]))
                print('---end '+path+'---')
            else:
                print(d)
        except Exception as e:
            print('parse_error', e)
    elif p.stderr.strip():
        print('\n'.join(p.stderr.strip().splitlines()[:2]))
PY

